svg.script:
const t1 = document.getElementById("ledText1");
const t2 = document.getElementById("ledText2");

let pos1 = 750;
let pos2 = 750;

const end1 = 50 - t1.getComputedTextLength();
const end2 = 50 - t2.getComputedTextLength();

function animate(){

  pos1 -= 6;
  pos2 -= 6;

  if(pos1 < end1) pos1 = 750;
  if(pos2 < end2) pos2 = 750;

  t1.setAttribute("x", pos1);
  t2.setAttribute("x", pos2);

  requestAnimationFrame(animate);
}

animate();
